@page "/Account/Login"
@using Microsoft.AspNetCore.Identity
@using sv_c18d385f789d4b7dbe84797c76ccdece.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Log in</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h2>Log in</h2>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <form method="post" @formname="login" @onsubmit="LoginUser">
            <AntiforgeryToken />
            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText id="email" @bind-Value="email" class="form-control" />
            </div>
            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <InputText id="password" @bind-Value="password" type="password" class="form-control" />
            </div>
            <button type="submit" class="btn btn-primary w-100">Log in</button>
        </form>
    </div>
</div>

@code {
    [SupplyParameterFromForm]
    private string email { get; set; } = "";

    [SupplyParameterFromForm]
    private string password { get; set; } = "";

    [SupplyParameterFromQuery]
    private string? returnUrl { get; set; }

    private string? errorMessage;

    private async Task LoginUser()
    {
        var result = await SignInManager.PasswordSignInAsync(email, password, isPersistent: false, lockoutOnFailure: false);
        if (result.Succeeded)
        {
            Navigation.NavigateTo(returnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }
}

@page "/Account/Logout"
@using Microsoft.AspNetCore.Identity
